def extract_zip(path, outdir):
    MAX_SIZE = 100 * 1024 * 1024  # 100 MB
    with zipfile.ZipFile(path) as zf:
        total = sum(fi.file_size for fi in zf.infolist())
        if total > MAX_SIZE:
            raise ValueError('archive too large')
        for fi in zf.infolist():
            dest = os.path.normpath(os.path.join(outdir, fi.filename))
            if not dest.startswith(os.path.normpath(outdir)):
                raise ValueError('path traversal in zip')
            if fi.file_size > MAX_SIZE // len(zf.infolist()):
                raise ValueError('file too large')
        zf.extractall(outdir)

